import { cn } from '@/utils/cn';
import { cva, VariantProps } from 'class-variance-authority';
import { Component, createUniqueId, mergeProps } from 'solid-js';

export type InputRadioProps = {
  type: 'radio';
  size?: RadioVariantsProps['size'];
  color?: RadioVariantsProps['color'];
  id?: string;
  name: string;
  value: string;
  checked?: boolean;
  disabled?: boolean;
  onChange?: (value: string) => void;
  class?: string;
};
const variants = cva('radio', {
  variants: {
    size: {
      xs: 'radio-xs',
      sm: 'radio-sm',
      md: 'radio-md',
      lg: 'radio-lg',
      xl: 'radio-xl',
    },
    color: {
      neutral: 'radio-neutral',
      primary: 'radio-primary',
      secondary: 'radio-secondary',
      accent: 'radio-accent',
      info: 'radio-info',
      success: 'radio-success',
      warning: 'radio-warning',
      error: 'radio-error',
    },
  },
});

export type RadioVariantsProps = VariantProps<typeof variants>;

export const InputRadio: Component<InputRadioProps> = p => {
  p = mergeProps({ size: 'md' as const, id: createUniqueId() }, p);
  return (
    <input
      type="radio"
      class={cn(variants({ color: p.color, size: p.size }), p.class)}
      id={p.id}
      name={p.name}
      value={p.value}
      checked={p.checked}
      disabled={p.disabled}
      onChange={e => p.onChange?.(e.currentTarget.value)}
    />
  );
};
